#include <stdio.h>
typedef long long ll;
#define rep(i,n) for(ll i=0; i<(ll)(n); i++)
const ll MOD = 1000000007;

/*nCk (mod MOD) BEGIN*/
//faccal -> n!, k!^(MOD-2)()
//comb -> nCk (mod MOD)
ll mlpow(ll x, ll p) { //(x^p) % MOD
    ll tmp = 1;
    if(p == 0) return 1;
    while(p != 0) {
        if(p & 1) tmp = tmp*x % MOD;
        x = x*x % MOD;
        p = p >> 1;
    }
    return tmp;
}

#define facnum 2000000
ll fac[facnum];     //n! (mod MOD)
ll facM2[facnum];   //(k!)^(MOD-2)
void faccal(ll up) {
    fac[0] = 1;
    facM2[0] = 1;
    for(ll i = 0; i < up + 1; i++){
        fac[i+1] = fac[i] * (i+1) % MOD;
        facM2[i+1] = facM2[i] * mlpow(i+1, MOD-2) % MOD;
    }
}

int main() {
    int N;
    scanf("%d", &N);

  	faccal(N);
	ll ans = (fac[N] - mlpow(2, N-1) + MOD) % MOD;
    printf("%lld\n", ans);
}

